use actix_web::{get, web};
use actix_files::Files;
use std::path::PathBuf;
use std::fs::File;
use std::io::prelude::*;


#[actix_rt::main]
async fn main() -> std::io::Result<()> {
    let app = actix_web::App::new().service(
        Files::new("/", PathBuf::from("./uploads"))
            .show_files_listing(),
    );

    println!("Starting server at 127.0.0.1:8080");
    app.bind("127.0.0.1:8080")?.run().await
}


#[get("/{file_name}")]
async fn file(path: web::Path<String>, data: actix_web::HttpRequest) -> actix_web::Result<actix_files::NamedFile> {
    let file = File::open("./uploads/" + &path).expect("file not found");

    Ok(actix_files::NamedFile::from_file(file)?
        .set_content_disposition(actix_files::ContentDisposition::Inline)
        .set_mime_type(data.match_info().get("file_name").unwrap())
    )
}